// --- Bot detection and anomaly tracking ---
class AnomalyTracker {
  constructor() {
    this.userAnomalies = new Map();
    this.ANOMALY_THRESHOLD = 5;
    this.DECAY_INTERVAL_MS = 30 * 60 * 1000;
  }

  recordAnomaly(userId, type, details) {
    if (!this.userAnomalies.has(userId)) {
      this.userAnomalies.set(userId, []);
    }
    const anomalies = this.userAnomalies.get(userId);
    anomalies.push({
      type,
      details: String(details).substring(0, 200),
      timestamp: Date.now()
    });

    // Prune old anomalies
    const cutoff = Date.now() - this.DECAY_INTERVAL_MS;
    const filtered = anomalies.filter(a => a.timestamp > cutoff);
    this.userAnomalies.set(userId, filtered);

    // Log anomaly without sensitive data
    console.warn(`Anomaly detected: userId=${userId}, type=${type}`);

    return filtered.length;
  }

  isUserFlagged(userId) {
    if (!this.userAnomalies.has(userId)) return false;
    const cutoff = Date.now() - this.DECAY_INTERVAL_MS;
    const recent = this.userAnomalies.get(userId).filter(a => a.timestamp > cutoff);
    return recent.length >= this.ANOMALY_THRESHOLD;
  }

  getAnomalyCount(userId) {
    if (!this.userAnomalies.has(userId)) return 0;
    const cutoff = Date.now() - this.DECAY_INTERVAL_MS;
    return this.userAnomalies.get(userId).filter(a => a.timestamp > cutoff).length;
  }
}

const anomalyTracker = new AnomalyTracker();

// --- Utility functions ---
function generateSecureToken(length = 32) {
  return crypto.randomBytes(length).toString('hex');
}

function computeHMAC(data) {
  return crypto.createHmac('sha256', HMAC_SECRET).update(JSON.stringify(data)).digest('hex');
}

function verifyHMAC(data, providedHmac) {
  const computed = computeHMAC(data);
  return crypto.timingSafeEqual(Buffer.from(computed, 'hex'), Buffer.from(providedHmac, 'hex'));
}

function sanitizeString(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/[<>"'&]/g, '').trim().substring(0, 100);
}

// Server-side reward calculation (never trust client for reward values)
function calculateReward(levelId, score, timeSeconds, moves) {
  const levelDef = LEVEL_DEFINITIONS[levelId];
  if (!levelDef) return null;

  // Base rewards from server-authoritative definitions
  let coins = levelDef.rewardCoins;
  let stars = levelDef.rewardStars;

  // Score-based bonus (server calculates, not client)
  const scoreRatio = Math.min(score / levelDef.maxScore, 1.0);
  const scoreBonus = Math.floor(coins * scoreRatio * 0.5);

  // Time-based bonus (faster completion within valid range)
  const timeRange = levelDef.maxTime - levelDef.minTime;
  const timeRatio = Math.max(0, 1 - ((timeSeconds - levelDef.minTime) / timeRange));
  const timeBonus = Math.floor(coins * timeRatio * 0.3);

  // Efficiency bonus based on moves
  const moveEfficiency = Math.max(0, 1 - (moves / levelDef.maxMoves));
  const moveBonus = Math.floor(coins * moveEfficiency * 0.2);

  return {
    coins: coins + scoreBonus + timeBonus + moveBonus,
    stars: stars,
    scoreBonus,
    timeBonus,
    moveBonus
  };
}

// --- Authentication middleware ---
function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required.' });
  }

  const token = authHeader.substring(7);

  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],
      maxAge: '24h'
    });

    if (!decoded.userId || !users.has(decoded.userId)) {
      return res.status(401).json({ error: 'Invalid token.' });
    }

    // Check if user is flagged for bot behavior
    if (anomalyTracker.isUserFlagged(decoded.userId)) {
      return res.status(403).json({ error: 'Account temporarily restricted due to suspicious activity.' });
    }

    req.userId = decoded.userId;
    req.user = users.get(decoded.userId);
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid or expired token.' });
  }
}

// --- Validation helpers ---
function handleValidationErrors(req, res) {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ error: 'Invalid input.', details: errors.array().map(e => e.msg) });
  }
  return null;
}

